8	 * the user reads them as read-only context, not host-authored geometry.
9	 *
10	 * Implementation: clone each material, dial the clone to a translucent blue
11	 * tint, and replace the mesh's material reference. We clone rather than
12	 * mutate because meshBuilders cache materials by reference; mutating in
13	 * place would ghost host meshes that share the same material.
14	 *
15	 * Idempotent — guarded by `userData.linkedGhost`.
16	 */
17	
18	export const LINKED_GHOST_OPACITY = 0.6;
19	export const LINKED_GHOST_TINT = '#5b8def';
20	
