22	  if (obj.userData.linkedGhost) return;
23	  obj.userData.linkedGhost = true;
24	  obj.userData.linked = true;
25	  const tint = new THREE.Color(LINKED_GHOST_TINT);
26	  obj.traverse((node) => {
27	    if (!(node instanceof THREE.Mesh)) return;
28	    const mat = node.material as THREE.Material | THREE.Material[] | undefined;
29	    if (!mat) return;
30	    const ghostOne = (m: THREE.Material): THREE.Material => {
31	      const clone = m.clone();
32	      clone.transparent = true;
33	      clone.opacity = LINKED_GHOST_OPACITY;
34	      clone.depthWrite = false;
35	      const anyMat = clone as THREE.Material & { color?: THREE.Color };
36	      if (anyMat.color instanceof THREE.Color) {
37	        anyMat.color.lerp(tint, 0.4);
38	      }
39	      return clone;
40	    };
41	    if (Array.isArray(mat)) {
42	      node.material = mat.map(ghostOne);
43	    } else {
44	      node.material = ghostOne(mat);
45	    }
